    and cc.customer_channel_code like concat('%', #{customerChannelCode}, '%')


    and cc.customer_channel_name like concat('%', #{customerChannelName}, '%')


    and cc.channel_type = #{channelType}


    and cc.standard_carrier_code = #{standardCarrierCode}


    and cc.status = #{status}

order by cc.display_order asc, cc.customer_channel_code asc

